class Solution {
    public int calculate(String s) {
        Stack<Character> stack = new Stack<>();
        int result = 0;
        int power = 0;

        for (char c : s.toCharArray()) {
            if (Character.isDigit(c)) {
                result = result * 10 + (c - '0');
            } else if (c == '+' || c == '-' || c == '*' || c == '/') {
                int op1 = stack.pop();
                int op2 = stack.pop();

                switch (c) {
                    case '+':
                        result = op2 + op1;
                        break;
                    case '-':
                        result = op2 - op1;
                        break;
                    case '*':
                        result = op2 * op1;
                        break;
                    case '/':
                        result = op2 / op1;
                        break;
                }
                stack.push(op1);
                stack.push(op2);
            }
        }
        return result;
    }
}
